function readLocalNumber(key, fallback = 0) {
    try {
        const value = Number(localStorage.getItem(key));
        return Number.isFinite(value) ? value : fallback;
    } catch (_) {
        return fallback;
    }
}

function writeLocalNumber(key, value) {
    try {
        localStorage.setItem(key, String(Number(value) || 0));
    } catch (_) { }
}

function getAdditionsCacheWriteBackoffUntil() {
    return readLocalNumber(ADDITIONS_CACHE_BACKOFF_KEY, 0);
}

function shouldSkipAdditionsCacheWrite() {
    const backoffUntil = getAdditionsCacheWriteBackoffUntil();
    return backoffUntil > Date.now();
}

function markAdditionsCacheWriteBackoff(message = '') {
    if (!isQuotaExceededErrorMessage(message)) return;
    const until = Date.now() + ADDITIONS_CACHE_WRITE_BACKOFF_MS;
    writeLocalNumber(ADDITIONS_CACHE_BACKOFF_KEY, until);
}

function clearAdditionsCacheWriteBackoff() {
    writeLocalNumber(ADDITIONS_CACHE_BACKOFF_KEY, 0);
}

function markAdditionsTreeRefreshTime(ts = Date.now()) {
    writeLocalNumber(ADDITIONS_TREE_REFRESH_TS_KEY, ts);
}

function shouldRefreshAdditionsTreeInBackground() {
    if (!isSidePanelMode) return true;
    const lastRefreshTs = readLocalNumber(ADDITIONS_TREE_REFRESH_TS_KEY, 0);
    if (!lastRefreshTs) return true;
    return (Date.now() - lastRefreshTs) >= SIDEPANEL_TREE_REFRESH_COOLDOWN_MS;
}

function shouldRunSidePanelPreload(markerKey, cooldownMs) {
    if (!isSidePanelMode) return true;
    const now = Date.now();
    const lastTs = readLocalNumber(markerKey, 0);
    if (lastTs && (now - lastTs) < cooldownMs) {
        return false;
    }
    writeLocalNumber(markerKey, now);
    return true;
}

function shouldRunSidePanelIconPreload() {
    return shouldRunSidePanelPreload(SIDEPANEL_ICON_PRELOAD_TS_KEY, SIDEPANEL_ICON_PRELOAD_COOLDOWN_MS);
}

function shouldRunSidePanelFaviconWarmup() {
    return shouldRunSidePanelPreload(SIDEPANEL_FAVICON_WARMUP_TS_KEY, SIDEPANEL_FAVICON_WARMUP_COOLDOWN_MS);
}

function readCachedValue(key) {
    return new Promise((resolve) => {
        const storageArea = getCacheStorageArea();
        if (storageArea) {
            storageArea.get([key], (result) => {
                if (browserAPI.runtime && browserAPI.runtime.lastError) {
                    console.warn('[Cache] 读取失败:', browserAPI.runtime.lastError.message);
                    resolve(null);
                    return;
                }
                resolve(result ? result[key] : null);
            });
            return;
        }

        try {
            const raw = localStorage.getItem(key);
            resolve(raw ? JSON.parse(raw) : null);
        } catch (error) {
            console.warn('[Cache] 读取 localStorage 失败:', error);
            resolve(null);
        }
    });
}

function setCachedValueToStorage(storageArea, key, value) {
    return new Promise((resolve) => {
        storageArea.set({ [key]: value }, () => {
            if (browserAPI.runtime && browserAPI.runtime.lastError) {
                resolve(browserAPI.runtime.lastError.message || String(browserAPI.runtime.lastError));
                return;
            }
            resolve(null);
        });
    });
}

function isQuotaExceededErrorMessage(message) {
    if (!message || typeof message !== 'string') return false;
    const normalized = message.toLowerCase();
    return normalized.includes('quota') || normalized.includes('kquotabytes') || normalized.includes('exceeded');
}

function buildAdditionsCachePayloadVariant(payload, options = {}) {
    if (!payload || !Array.isArray(payload.bookmarks)) {
        return payload;
    }

    const {
        omitPath = false,
        omitAncestors = false,
        maxBookmarks = Infinity
    } = options;

    const source = payload.bookmarks;
    const limited = Number.isFinite(maxBookmarks) ? source.slice(0, Math.max(0, maxBookmarks)) : source;

    const bookmarks = limited
        .map((entry) => {
            if (!entry || !entry.url) return null;

            const dateAdded = typeof entry.dateAdded === 'number'
                ? entry.dateAdded
                : (entry.dateAdded instanceof Date ? entry.dateAdded.getTime() : Date.now());

            return {
                id: entry.id,
                title: entry.title || entry.url || '',
                url: entry.url || '',
                dateAdded,
                parentId: entry.parentId || '',
                path: omitPath ? '' : (entry.path || ''),
                ancestorFolderIds: omitAncestors
                    ? []
                    : (Array.isArray(entry.ancestorFolderIds)
                        ? entry.ancestorFolderIds.filter(id => id != null).map(id => String(id))
                        : [])
            };
        })
        .filter(Boolean);

    return {
        timestamp: payload.timestamp || Date.now(),
        totalBookmarks: source.length,
        truncated: Number.isFinite(maxBookmarks) ? source.length > bookmarks.length : false,
        compact: omitPath || omitAncestors || Number.isFinite(maxBookmarks),
        bookmarks
    };
}

function writeCachedValue(key, value) {
    return new Promise(async (resolve) => {
        const isAdditionsCache = key === DATA_CACHE_KEYS.additions;
        if (isAdditionsCache && shouldSkipAdditionsCacheWrite()) {
            resolve({ ok: false, error: 'write_backoff' });
            return;
        }

        const storageArea = getCacheStorageArea();
        if (storageArea) {
            let writeError = await setCachedValueToStorage(storageArea, key, value);
            if (!writeError) {
                if (isAdditionsCache) clearAdditionsCacheWriteBackoff();
                resolve({ ok: true, compact: false });
                return;
            }

            if (
                isAdditionsCache
                && value
                && Array.isArray(value.bookmarks)
                && isQuotaExceededErrorMessage(writeError)
            ) {
                const fallbackStrategies = [
                    { label: 'drop-path', options: { omitPath: true } },
                    { label: 'drop-path-ancestor', options: { omitPath: true, omitAncestors: true } },
                    { label: 'trim-12000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 12000 } },
                    { label: 'trim-8000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 8000 } },
                    { label: 'trim-5000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 5000 } },
                    { label: 'trim-3000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 3000 } },
                    { label: 'trim-2000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 2000 } },
                    { label: 'trim-1000', options: { omitPath: true, omitAncestors: true, maxBookmarks: 1000 } },
                    { label: 'trim-600', options: { omitPath: true, omitAncestors: true, maxBookmarks: 600 } },
                    { label: 'trim-300', options: { omitPath: true, omitAncestors: true, maxBookmarks: 300 } }
                ];

                for (const strategy of fallbackStrategies) {
                    const fallbackPayload = buildAdditionsCachePayloadVariant(value, strategy.options);
                    const fallbackError = await setCachedValueToStorage(storageArea, key, fallbackPayload);
                    if (!fallbackError) {
                        clearAdditionsCacheWriteBackoff();
                        console.warn(`[Cache] 添加记录缓存超限，已降级保存(${strategy.label}): ${fallbackPayload.bookmarks.length}/${value.bookmarks.length}`);
                        resolve({
                            ok: true,
                            compact: true,
                            strategy: strategy.label,
                            savedBookmarks: fallbackPayload.bookmarks.length,
                            totalBookmarks: value.bookmarks.length
                        });
                        return;
                    }
                    writeError = fallbackError;
                }
            }

            if (isAdditionsCache) {
                markAdditionsCacheWriteBackoff(writeError);
            }
            console.warn('[Cache] 写入失败:', writeError);
            resolve({ ok: false, error: writeError });
            return;
        }

        try {
            localStorage.setItem(key, JSON.stringify(value));
            if (isAdditionsCache) clearAdditionsCacheWriteBackoff();
            resolve({ ok: true, compact: false });
        } catch (error) {
            if (isAdditionsCache) {
                markAdditionsCacheWriteBackoff(error?.message || String(error));
            }
            console.warn('[Cache] 写入 localStorage 失败:', error);
            resolve({ ok: false, error: error?.message || String(error) });
        }
    });
}


function normalizeBookmarkCacheEntry(entry) {
    if (!entry || !entry.url) return null;
    const timestamp = typeof entry.dateAdded === 'number'
        ? entry.dateAdded
        : (entry.dateAdded instanceof Date ? entry.dateAdded.getTime() : Date.now());
    const ancestorFolderIds = Array.isArray(entry.ancestorFolderIds)
        ? entry.ancestorFolderIds.filter(id => id != null).map(id => String(id))
        : [];
    return {
        id: entry.id,
        title: entry.title || entry.url || '',
        url: entry.url || '',
        dateAdded: timestamp,
        parentId: entry.parentId || '',
        path: entry.path || '',
        ancestorFolderIds
    };
}

function getAdditionsSnapshotDateKey(value) {
    const date = value instanceof Date ? new Date(value) : new Date(value);
    if (Number.isNaN(date.getTime())) return '';
    return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

function buildAdditionsWidgetsSnapshotFromEntries(entries = []) {
    const safeDays = Math.max(14, Number(ADDITIONS_WIDGETS_SNAPSHOT_DAYS) || 45);
    const base = new Date();
    base.setHours(0, 0, 0, 0);

    const countByKey = Object.create(null);
    for (let i = safeDays - 1; i >= 0; i -= 1) {
        const date = new Date(base);
        date.setDate(base.getDate() - i);
        countByKey[getAdditionsSnapshotDateKey(date)] = 0;
    }

    (Array.isArray(entries) ? entries : []).forEach((entry) => {
        const rawTs = Number(entry?.dateAdded || 0);
        if (!Number.isFinite(rawTs) || rawTs <= 0) return;
        const key = getAdditionsSnapshotDateKey(rawTs);
        if (!key || !Object.prototype.hasOwnProperty.call(countByKey, key)) return;
        countByKey[key] = Number(countByKey[key] || 0) + 1;
    });

    return {
        ts: Date.now(),
        days: safeDays,
        countByKey
    };
}

function readAdditionsWidgetsSnapshot() {
    try {
        const raw = localStorage.getItem(ADDITIONS_WIDGETS_SNAPSHOT_KEY);
        if (!raw) return null;
        const parsed = JSON.parse(raw);
        if (!parsed || typeof parsed !== 'object') return null;
        if (!parsed.countByKey || typeof parsed.countByKey !== 'object') return null;
        return {
            ts: Number(parsed.ts || 0),
            days: Number(parsed.days || 0),
            countByKey: parsed.countByKey
        };
    } catch (_) {
        return null;
    }
}

function persistAdditionsWidgetsSnapshot(entries = allBookmarks) {
    try {
        const snapshot = buildAdditionsWidgetsSnapshotFromEntries(entries);
        localStorage.setItem(ADDITIONS_WIDGETS_SNAPSHOT_KEY, JSON.stringify(snapshot));
        return snapshot;
    } catch (_) {
        return null;
    }
}

function scheduleAdditionsWidgetsSnapshotSave() {
    if (saveAdditionsWidgetsSnapshotTimer) {
        clearTimeout(saveAdditionsWidgetsSnapshotTimer);
    }
    saveAdditionsWidgetsSnapshotTimer = setTimeout(() => {
        saveAdditionsWidgetsSnapshotTimer = null;
        persistAdditionsWidgetsSnapshot(allBookmarks);
    }, 320);
}

async function ensureAdditionsCacheLoaded(skipRender) {
    if (additionsCacheRestored || allBookmarks.length > 0) {
        return;
    }
    if (additionsCacheLoadPromise) {
        await additionsCacheLoadPromise;
        return;
    }

    additionsCacheLoadPromise = (async () => {
        try {
            const cached = await readCachedValue(DATA_CACHE_KEYS.additions);
            if (cached && Array.isArray(cached.bookmarks)) {
                allBookmarks = cached.bookmarks
                    .map(normalizeBookmarkCacheEntry)
                    .filter(Boolean);
                additionsCacheRestored = true;
                rebuildBookmarkUrlSet();
                persistAdditionsWidgetsSnapshot(allBookmarks);

                if (currentView === 'widgets') {
                    markWidgetsDirty('additionsWeek', { schedule: false });
                    updateWidgetsViewData({
                        targets: ['additionsWeek'],
                        bypassVisualGate: true,
                        allowDuringInteraction: true
                    }).catch(() => { });
                } else if (!skipRender && currentView === 'additions') {
                    renderAdditionsView();
                }
            }
        } catch {
        }
    })();

    try {
        await additionsCacheLoadPromise;
    } finally {
        additionsCacheLoadPromise = null;
    }
}

async function persistAdditionsCache() {
    try {
        const payload = {
            timestamp: Date.now(),
            bookmarks: allBookmarks.map(normalizeBookmarkCacheEntry).filter(Boolean)
        };

        const result = await writeCachedValue(DATA_CACHE_KEYS.additions, payload);
        if (result && result.ok === false) {
            return;
        }

        if (result && result.compact) {

            return;
        }


    } catch (error) {
        console.warn('[AdditionsCache] 保存失败:', error);
    }
}

function scheduleAdditionsCacheSave() {
    if (saveAdditionsCacheTimer) {
        clearTimeout(saveAdditionsCacheTimer);
    }
    saveAdditionsCacheTimer = setTimeout(() => {
        saveAdditionsCacheTimer = null;
        persistAdditionsCache();
    }, 600);
}

function handleAdditionsDataMutation(forceRender = true) {
    additionsCacheRestored = true;
    clearWidgetsTrendDataCaches({ additionsOnly: true });
    markWidgetsDirty('additionsWeek', { delayMs: 120 });
    scheduleAdditionsCacheSave();
    scheduleAdditionsWidgetsSnapshotSave();
    if (forceRender && currentView === 'additions') {
        renderAdditionsView();
    }
}

function addBookmarkToAdditionsCache(bookmark) {
    const normalized = normalizeBookmarkCacheEntry(bookmark);
    if (!normalized) return;
    allBookmarks.push(normalized);
    addUrlToBookmarkSet(normalized.url);
    const normalizedTitle = normalizeBookmarkTitle(normalized.title);
    if (normalizedTitle) {
        bookmarkTitleSet.add(normalizedTitle);
    }
    handleAdditionsDataMutation(true);
}

function removeBookmarkFromAdditionsCache(bookmarkId) {
    if (!bookmarkId) return;
    const index = allBookmarks.findIndex(item => item.id === bookmarkId);
    if (index === -1) return;
    removeUrlFromBookmarkSet(allBookmarks[index].url);
    allBookmarks.splice(index, 1);
    handleAdditionsDataMutation(true);
}

function updateBookmarkInAdditionsCache(bookmarkId, changeInfo = {}) {
    if (!bookmarkId) return;
    const target = allBookmarks.find(item => item.id === bookmarkId);
    if (!target) return;
    const prevUrl = target.url;
    if (typeof changeInfo.title !== 'undefined') {
        target.title = changeInfo.title;
        const normalizedTitle = normalizeBookmarkTitle(changeInfo.title);
        if (normalizedTitle) {
            bookmarkTitleSet.add(normalizedTitle);
        }
    }
    if (typeof changeInfo.url !== 'undefined') {
        target.url = changeInfo.url;
        removeUrlFromBookmarkSet(prevUrl);
        addUrlToBookmarkSet(changeInfo.url);
    }
    handleAdditionsDataMutation(true);
}

function moveBookmarkInAdditionsCache(bookmarkId, moveInfo = {}) {
    if (!bookmarkId) return;
    const target = allBookmarks.find(item => item.id === bookmarkId);
    if (!target) return;
    if (typeof moveInfo.parentId !== 'undefined') {
        target.parentId = moveInfo.parentId;
    }
    handleAdditionsDataMutation(false);
}

function normalizeBookmarkTitle(title) {
    if (!title || typeof title !== 'string') return null;
    const trimmed = title.trim();
    return trimmed || null;
}

function normalizeBookmarkUrl(url) {
    if (!url || typeof url !== 'string') return null;
    if (!url.startsWith('http://') && !url.startsWith('https://')) {
        return null;
    }
    return url.trim();
}

function rebuildBookmarkUrlSet() {
    bookmarkUrlSet.clear();
    bookmarkTitleSet.clear();
    allBookmarks.forEach(item => {
        const normalized = normalizeBookmarkUrl(item.url);
        if (normalized) {
            bookmarkUrlSet.add(normalized);
        }
        const normalizedTitle = normalizeBookmarkTitle(item.title);
        if (normalizedTitle) {
            bookmarkTitleSet.add(normalizedTitle);
        }
    });
}

function addUrlToBookmarkSet(url) {
    const normalized = normalizeBookmarkUrl(url);
    if (normalized) {
        bookmarkUrlSet.add(normalized);
    }
}

function removeUrlFromBookmarkSet(url) {
    const normalized = normalizeBookmarkUrl(url);
    if (normalized) {
        bookmarkUrlSet.delete(normalized);
    }
}

function scheduleHistoryRefresh({ forceFull = false } = {}) {

    pendingHistoryRefreshForceFull = pendingHistoryRefreshForceFull || forceFull;
    if (pendingHistoryRefreshTimer) {
        clearTimeout(pendingHistoryRefreshTimer);
    }
    pendingHistoryRefreshTimer = setTimeout(() => {

        pendingHistoryRefreshTimer = null;
        const shouldForce = pendingHistoryRefreshForceFull;
        pendingHistoryRefreshForceFull = false;
        refreshBrowsingHistoryData({ forceFull: shouldForce, silent: true });
    }, 500);
}

function getRecommendCardsRefreshDebounceMs(changes = null) {
    const keys = changes && typeof changes === 'object' ? Object.keys(changes) : [];

    const heavySignals = [
        'recommend_scores_cache',
        RECOMMEND_POSTPONED_STORAGE_KEY,
        RECOMMEND_BLOCKED_STORAGE_KEY,
        'lastBookmarkData',
        'lastSyncOperations',
        'lastSyncTime',
        'bookmarkBulkChangeFlag'
    ];

    const hasHeavySignal = keys.some(key => heavySignals.includes(key));
    const base = hasHeavySignal ? 1200 : 900;

    const now = Date.now();
    const sinceLast = now - lastRecommendCardsRefreshAt;
    if (sinceLast < 600) {
        return Math.max(base, 1500);
    }

    return base;
}

function handleHistoryVisited(result) {
    if (!result || !result.url) return;

    scheduleHistoryRefresh({ forceFull: false });
}

async function handleHistoryVisitRemoved(details) {
    if (!details) return;


    const urls = Array.isArray(details.urls) ? details.urls.filter(Boolean) : [];
    if (!details.allHistory && urls.length === 0 && typeof showToast === 'function') {
        const msg = currentLang === 'zh_CN'
            ? '检测到历史删除，但未提供URL列表，可手动校准。'
            : 'History removed without URL list; you can calibrate manually.';
        showToast(msg, 4000);
    }
    scheduleBrowsingCalibrationCountRefresh();
}
let historyRealtimeBound = false;
let messageListenerRegistered = false;
let historyPollingTimer = null;
let bookmarkListenerRegistered = false;
let storageListenerRegistered = false;
let lastRecommendCardsRefreshAt = 0;
let recommendCardsRefreshDebounceMs = 900;
let lastStorageChanges = null;
let quickReviewActionInFlight = false;
let quickReviewOpenMode = readQuickReviewOpenMode();
let recommendCandidatesPreloadTimer = null;
let recommendCandidatesPreloadInFlight = false;
let recommendCandidatesPreloadQueuedLimit = 0;
let recommendCandidatesPreloadLastRunAt = 0;
syncQuickReviewOpenModeToBackground(quickReviewOpenMode);

function ensureHistoryPolling() {
    if (historyPollingTimer) return;
    // 兜底轮询：防止 onVisited/onVisitRemoved 在某些环境下不触发
    historyPollingTimer = setInterval(() => {
        try {
            if (currentView !== 'additions') return;
            refreshBrowsingHistoryData({ forceFull: false, silent: true });
        } catch (_) { }
    }, 120000); // 2分钟一次
}

function setupBrowsingHistoryRealtimeListeners() {
    if (historyRealtimeBound) {

        return;
    }
    if (!browserAPI.history) {
        console.warn('[History] 浏览器历史API不可用');
        ensureHistoryPolling();
        return;
    }
    if (browserAPI.history.onVisited && typeof browserAPI.history.onVisited.addListener === 'function') {

        browserAPI.history.onVisited.addListener(handleHistoryVisited);
        historyRealtimeBound = true;
    }
    if (browserAPI.history.onVisitRemoved && typeof browserAPI.history.onVisitRemoved.addListener === 'function') {

        browserAPI.history.onVisitRemoved.addListener(handleHistoryVisitRemoved);
    }
    if (!historyRealtimeBound) {
        ensureHistoryPolling();
    }
}

async function refreshBrowsingHistoryData(options = {}) {
    const { forceFull = false, silent = false } = options;
    const inst = window.browsingHistoryCalendarInstance;
    if (!inst || typeof inst.loadBookmarkData !== 'function') {
        return;
    }

    if (browsingHistoryRefreshPromise) {
        try {
            await browsingHistoryRefreshPromise;
        } catch (_) {
        }
    }

    const incremental = !forceFull && !!(inst.historyCacheMeta && inst.historyCacheMeta.lastSyncTime);
    browsingHistoryRefreshPromise = (async () => {
        try {
            await inst.loadBookmarkData({ incremental });

            if (typeof rebuildBookmarkUrlSet === 'function' && allBookmarks.length > 0) {
                rebuildBookmarkUrlSet();
            }

            if (typeof inst.render === 'function') {
                inst.render();
            }
            if (typeof inst.updateSelectModeButton === 'function') {
                inst.updateSelectModeButton();
            }

            resetBrowsingRankingDerivedCache();
            clearWidgetsTrendDataCaches({ historyOnly: true });
            markWidgetsDirty(['ranking', 'related', 'historyWeek'], { delayMs: 120 });
        } catch (error) {
            if (!silent) {
                console.warn('[BrowsingHistory] 刷新失败:', error);
            }
            throw error;
        } finally {
            browsingHistoryRefreshPromise = null;
        }
    })();

    try {
        await browsingHistoryRefreshPromise;
    } catch (_) {
    }
}

async function refreshBrowsingHistoryFromCache({ silent = true } = {}) {
    const inst = window.browsingHistoryCalendarInstance;
    if (!inst) return;

    if (browsingHistoryRefreshPromise) {
        try {
            await browsingHistoryRefreshPromise;
        } catch (_) { }
    }

    try {
        if (inst.useNewArchitecture && inst.dbManager && typeof inst.syncFromDatabaseManager === 'function') {
            inst.syncFromDatabaseManager();
            if (typeof inst.render === 'function') inst.render();
            if (typeof inst.updateSelectModeButton === 'function') inst.updateSelectModeButton();
        } else if (typeof inst.getViewDateRange === 'function' && typeof inst.getRangeKeys === 'function' && typeof inst.loadViewRangeFromCache === 'function') {
            const range = inst.getViewDateRange();
            if (range) {
                const { startKey, endKey } = inst.getRangeKeys(range);
                await inst.loadViewRangeFromCache(startKey, endKey);
                if (typeof inst.render === 'function') inst.render();
                if (typeof inst.updateSelectModeButton === 'function') inst.updateSelectModeButton();
            }
        }

        resetBrowsingRankingDerivedCache();
        clearWidgetsTrendDataCaches({ historyOnly: true });
        markWidgetsDirty(['ranking', 'related', 'historyWeek'], { delayMs: 120 });
        document.dispatchEvent(new CustomEvent('browsingHistoryCacheUpdated'));
    } catch (error) {
        if (!silent) {
            console.warn('[BrowsingHistory] 缓存刷新失败:', error);
        }
    }
}

