// =============================================================================
// 初始化
// =============================================================================

document.addEventListener('DOMContentLoaded', async () => {


    // ========================================================================
    // 【关键步骤 -1】检测是否需要清除 localStorage（"恢复到初始状态"功能触发）
    // ========================================================================
    try {
        const resetCheck = await new Promise(resolve => {
            browserAPI.storage.local.get(['needClearLocalStorage'], result => resolve(result));
        });

        if (resetCheck && resetCheck.needClearLocalStorage === true) {


            // 清除当前页面上下文的所有 localStorage
            localStorage.clear();

            // 移除重置标志（避免重复清除）
            await new Promise(resolve => {
                browserAPI.storage.local.remove(['needClearLocalStorage'], resolve);
            });


        }
    } catch (error) {
        console.warn('[初始化] 检测重置标志时出错:', error);
    }

    // ========================================================================
    // 【关键步骤 0】初始化 Favicon 缓存系统
    // ========================================================================
    try {
        await FaviconCache.init();
    } catch (error) {
        // 静默处理
    }


    // 设置全局图片错误处理（避免CSP内联事件处理器）
    setupGlobalImageErrorHandler();

    // ========================================================================
    // 【关键步骤 1】最优先：立即恢复并应用视图状态
    // ========================================================================
    const urlParams = new URLSearchParams(window.location.search);
    const viewParam = urlParams.get('view');
    let requestedView = null;
    try {
        const result = await new Promise(resolve => {
            browserAPI.storage.local.get(['historyRequestedView'], resolve);
        });
        const payload = result?.historyRequestedView || null;
        const withinWindow = payload && typeof payload.time === 'number'
            ? (Date.now() - payload.time) < 15000
            : false;
        if (withinWindow && payload?.view) {
            requestedView = payload.view;
        }
    } catch (_) { }

    const updateViewParamInUrl = (view) => {
        if (isSidePanelMode) return;
        try {
            const url = new URL(window.location.href);
            url.searchParams.set('view', view);
            window.history.replaceState({}, '', url.toString());
        } catch (_) { }
    };

    // 优先级：URL参数 > localStorage > 默认值
    if (viewParam && ALLOWED_VIEWS.includes(viewParam)) {
        currentView = viewParam;

        updateViewParamInUrl(currentView);
    } else if (requestedView && ALLOWED_VIEWS.includes(requestedView)) {
        currentView = requestedView;

        updateViewParamInUrl(currentView);
    } else {
        const lastView = localStorage.getItem(LAST_ACTIVE_VIEW_STORAGE_KEY);
        if (lastView && ALLOWED_VIEWS.includes(lastView)) {
            currentView = lastView;

        } else {
            currentView = DEFAULT_VIEW;

        }
        updateViewParamInUrl(currentView);
    }

    if (requestedView) {
        try {
            await new Promise(resolve => {
                browserAPI.storage.local.remove(['historyRequestedView'], resolve);
            });
        } catch (_) { }
    }

    // 如果后台请求打开刷新设置弹窗（推荐视图）
    try {
        const result = await new Promise(resolve => {
            browserAPI.storage.local.get(['openRecommendRefreshSettings'], resolve);
        });
        if (result?.openRecommendRefreshSettings) {
            setTimeout(() => {
                try { showRefreshSettingsModal(); } catch (_) { }
            }, 200);
            browserAPI.storage.local.remove(['openRecommendRefreshSettings'], () => {});
        }
    } catch (_) { }

    // 立即应用视图状态到DOM
    try { window.currentView = currentView; } catch (_) { }

    document.querySelectorAll('.nav-tab').forEach(tab => {
        if (tab.dataset.view === currentView) {
            tab.classList.add('active');
        } else {
            tab.classList.remove('active');
        }
    });
    document.querySelectorAll('.view').forEach(view => {
        if (view.id === `${currentView}View`) {
            view.classList.add('active');
        } else {
            view.classList.remove('active');
        }
    });

    localStorage.setItem(LAST_ACTIVE_VIEW_STORAGE_KEY, currentView);
    updatePageHeaderTitle(currentView);

    if (isSidePanelMode && currentView === 'widgets') {
        syncWidgetsOpenStabilizingState();
    }


    // [Search Context Boot] 首次加载时同步 SearchContextManager 的 view/tab/subTab。
    // 这里不能依赖 switchView()，因为初始化阶段是直接改 DOM 来显示视图。
    try {
        if (window.SearchContextManager && typeof window.SearchContextManager.updateContext === 'function') {
            let tab = null;
            let subTab = null;
            if (currentView === 'additions') {
                tab = localStorage.getItem('additionsActiveTab') || 'review';
                if (tab === 'browsing') {
                    subTab = localStorage.getItem('browsingActiveSubTab') || 'history';
                }
            }
            window.SearchContextManager.updateContext(currentView, tab, subTab);
        }
    } catch (_) { }

    // ========================================================================
    // 其他初始化
    // ========================================================================



    // 加载用户设置
    await loadUserSettings();

    // 初始化 UI（此时currentView已经是正确的值）
    initializeUI();

    // 初始化侧边栏收起功能
    initSidebarToggle();

    // 初始化标题栏折叠/上下停靠
    initHeaderToggle();

    if (isViewAllowed('widgets')) {
        initWidgetsView();
    }

    // 初始化时间捕捉/追踪相关功能（仅在允许 additions 视图时）
    if (isViewAllowed('additions')) {
        initTimeTrackingWidget();
        initTrackingBlockModal();
        initSelectTrackingBlockFolderModal();
        initAddTrackingBlockDomainModal();
        initAddTrackingBlockBookmarkModal();
    }

    // 侧边栏：优先尝试快照秒显，后续由 storage/current round 做校准。
    if (isSidePanelMode) {
        try {
            await hydrateRecommendCardsFromSnapshotForSidePanel();
        } catch (_) { }
    }

    // 注册消息监听
    setupRealtimeMessageListener();

    let renderedCurrentViewEarly = false;
    if (isSidePanelMode && currentView === 'widgets') {
        if (widgetsSmartSortEnabled) {
            widgetsSortApplyDeferredInteractionsOnOpen = true;
            syncWidgetsOpenStabilizingState();
        }
        await renderCurrentView();
        renderedCurrentViewEarly = true;
    }

    // 先加载基础数据

    if (isSidePanelMode) {
        await ensureAdditionsCacheLoaded(true);
        const hasFastCache = additionsCacheRestored && Array.isArray(allBookmarks) && allBookmarks.length > 0;
        if (currentView === 'widgets') {
            // widgets 首开的数据源预热统一由 startWidgetsViewRefresh 执行，
            // 这里不再重复触发 loadAllData，避免首开链路并发打架导致延迟波动。
        } else if (hasFastCache) {
            loadAllData({ skipRender: true }).catch((error) => {
                console.warn('[初始化] 侧边栏后台刷新失败:', error);
            });

        } else {
            await loadAllData();
        }
    } else {
        await loadAllData();
    }

    // 侧边栏模式：打开次数计入自动刷新阈值（按侧边栏打开次数而不是主 UI）
    if (isSidePanelMode) {
        try {
            const shouldRefreshFromSidePanelOpen = await checkAndIncrementOpenCount({ source: 'sidepanel' });
            if (shouldRefreshFromSidePanelOpen) {
                const hasPendingRound = await hasPendingRecommendRoundState();
                if (!hasPendingRound) {
                    await refreshRecommendCards(true);
                    try {
                        lastWidgetsRecommendCardSignature = '';
                    } catch (_) { }
                }
            }
        } catch (error) {
            console.warn('[侧边栏] 处理推荐刷新阈值失败:', error);
        }
    }

    // 使用智能等待：尝试渲染，如果数据不完整则等待后重试
    // 初始化时强制刷新缓存，确保显示最新数据

    if (!renderedCurrentViewEarly) {
        if (isSidePanelMode && currentView === 'widgets' && widgetsSmartSortEnabled) {
            widgetsSortApplyDeferredInteractionsOnOpen = true;
            syncWidgetsOpenStabilizingState();
        }

        // 根据当前视图渲染
        await renderCurrentView();
    }

    try {
        await applyPendingWidgetsJumpContextFromNavToken(urlParams.get('nav'));
    } catch (_) { }

    // [View Sync] Ensure the URL param always wins after initial render (protect against late overrides)
    try {
        syncViewFromUrl('init');
        if (!window.__historyViewSyncBound) {
            window.__historyViewSyncBound = true;
            window.addEventListener('pageshow', () => syncViewFromUrl('pageshow'));
            window.addEventListener('popstate', () => syncViewFromUrl('popstate'));
        }
    } catch (_) { }

    // [Favicon Warmup] Preload favicon memory cache to avoid flicker when switching views
    try {
        const shouldWarmupFavicons = !isSidePanelMode || shouldRunSidePanelFaviconWarmup();
        if (shouldWarmupFavicons) {
            const rawUrls = allBookmarks
                .map(b => b && b.url)
                .filter(url => url && !FaviconCache.isInvalidUrl(url));
            const MAX_WARMUP = isSidePanelMode ? 120 : 300;
            const warmUrls = rawUrls.length > MAX_WARMUP ? rawUrls.slice(0, MAX_WARMUP) : rawUrls;
            if (warmUrls.length) {
                setTimeout(async () => {
                    try {
                        await warmupFaviconCache(warmUrls);
                        warmUrls.forEach((url) => {
                            const domain = FaviconCache._getHostnameFromUrl(url);
                            if (!domain) return;
                            const cached = FaviconCache.memoryCache.get(domain);
                            if (cached && cached !== fallbackIcon) {
                                updateFaviconImages(url, cached);
                            }
                        });
                    } catch (e) {
                        console.warn('[Favicon预热] 预热失败:', e);
                    }
                }, 0);
            }
        }
    } catch (_) { }

    try {
        const titleParam = urlParams.get('t');
        const typeParam = urlParams.get('type'); // 'hyperlink' 或 undefined

        if (titleParam && typeof titleParam === 'string' && titleParam.trim()) {
            // 根据type参数设置不同的标题格式
            if (typeParam === 'hyperlink') {
                // 超链接系统：使用 "Hyperlink N" 格式
                document.title = `Hyperlink ${titleParam.trim()}`;
            } else {
                // 书签系统：直接使用数字
                document.title = titleParam.trim();
            }
        }
    } catch (e) {
        console.warn('[初始化] 设置标题失败:', e);
    }

    // 并行预加载其他视图和图标（不阻塞）
    const preloadTasks = [preloadAllViews()];
    if (!isSidePanelMode || shouldRunSidePanelIconPreload()) {
        preloadTasks.push(preloadCommonIcons());
    }

    Promise.all(preloadTasks).then(() => {

    }).catch(error => {
        console.error('[初始化] 预加载失败:', error);
    });

    // 监听存储变化（实时更新）
    if (!storageListenerRegistered) {
        browserAPI.storage.onChanged.addListener(handleStorageChange);
        storageListenerRegistered = true;
    }

    // 监听书签API变化（实时更新书签树视图）
    setupBookmarkListener();
    if (isViewAllowed('additions') || isViewAllowed('recommend') || isViewAllowed('widgets')) {
        setupBrowsingHistoryRealtimeListeners();
    }


});

// =============================================================================
// 用户设置
// =============================================================================

// 检查是否有覆盖设置
function hasThemeOverride() {
    try {
        return localStorage.getItem('historyViewerHasCustomTheme') === 'true';
    } catch (e) {
        return false;
    }
}

function hasLangOverride() {
    try {
        return localStorage.getItem('historyViewerHasCustomLang') === 'true';
    } catch (e) {
        return false;
    }
}

// 获取覆盖设置
function getThemeOverride() {
    try {
        return localStorage.getItem('historyViewerCustomTheme');
    } catch (e) {
        return null;
    }
}

function getLangOverride() {
    try {
        return localStorage.getItem('historyViewerCustomLang');
    } catch (e) {
        return null;
    }
}

async function loadUserSettings() {
    return new Promise((resolve) => {
        browserAPI.storage.local.get(['preferredLang', 'currentTheme'], (result) => {
            const mainUILang = (result.preferredLang === 'zh_CN' || result.preferredLang === 'en')
                ? result.preferredLang
                : detectDefaultLang();
            const prefersDark = typeof window !== 'undefined'
                && window.matchMedia
                && window.matchMedia('(prefers-color-scheme: dark)').matches;
            const mainUITheme = result.currentTheme || (prefersDark ? 'dark' : 'light');

            // 优先使用覆盖设置，否则使用主UI设置
            if (hasThemeOverride()) {
                currentTheme = getThemeOverride() || mainUITheme;

            } else {
                currentTheme = mainUITheme;

            }

            if (hasLangOverride()) {
                currentLang = getLangOverride() || mainUILang;
                window.currentLang = currentLang; // 同步到 window

            } else {
                currentLang = mainUILang;
                window.currentLang = currentLang; // 同步到 window

            }

            // 应用主题
            if (currentTheme === 'dark') document.documentElement.setAttribute('data-theme', 'dark');
            else document.documentElement.removeAttribute('data-theme');

            // 更新主题切换按钮图标
            const themeIcon = document.querySelector('#themeToggle i');
            if (themeIcon) {
                themeIcon.className = currentTheme === 'dark' ? 'fas fa-sun' : 'fas fa-moon';
            }

            // 应用语言
            applyLanguage();

            // 更新语言切换按钮文本
            const langText = document.querySelector('#langToggle .lang-text');
            if (langText) {
                langText.textContent = currentLang === 'zh_CN' ? 'EN' : '中';
            }

            resolve();
        });
    });
}

function getViewTitleText(view = currentView) {
    const safeView = typeof view === 'string' ? view : '';
    if (safeView === 'widgets') return (i18n.sidePanelTitleWidgets && i18n.sidePanelTitleWidgets[currentLang]) || i18n.navWidgets[currentLang];
    if (safeView === 'additions') return (i18n.sidePanelTitleAdditions && i18n.sidePanelTitleAdditions[currentLang]) || i18n.navAdditions[currentLang];
    if (safeView === 'recommend') return (i18n.sidePanelTitleRecommend && i18n.sidePanelTitleRecommend[currentLang]) || i18n.navRecommend[currentLang];
    return i18n.pageTitle[currentLang];
}

let sidePanelHeaderTitleAlignRaf = null;

function syncSidePanelHeaderTitleAlignment() {
    if (!isSidePanelMode) return;
    document.documentElement.style.setProperty('--sidepanel-title-align-offset', '0px');
}

function scheduleSidePanelHeaderTitleAlignment() {

    if (!isSidePanelMode) return;
    if (sidePanelHeaderTitleAlignRaf != null) return;

    sidePanelHeaderTitleAlignRaf = window.requestAnimationFrame(() => {
        sidePanelHeaderTitleAlignRaf = null;
        syncSidePanelHeaderTitleAlignment();
    });
}

function updatePageHeaderTitle(view = currentView) {
    const pageTitleEl = document.getElementById('pageTitle');
    if (!pageTitleEl) return;

    pageTitleEl.textContent = getViewTitleText(view);

    if (isSidePanelMode) {
        scheduleSidePanelHeaderTitleAlignment();
    }

    updateWidgetsSmartSortToggleUI(view);
}

